import React, {useEffect, useMemo, useState} from 'react';
import {createRoot} from 'react-dom/client';
import {FiBell, FiCalendar, FiCheck, FiChevronDown, FiChevronLeft, FiChevronRight, FiClock, FiDownload, FiEye, FiFilter, FiHelpCircle, FiHome, FiLock, FiMail, FiMapPin, FiMenu, FiMinusCircle, FiMoreHorizontal, FiPhone, FiPlus, FiRefreshCw, FiSearch, FiSettings, FiUpload, FiUser} from 'react-icons/fi';
import {GiCarrot, GiCorn, GiFarmTractor, GiFertilizerBag, GiGrain, GiPlantRoots, GiPotato, GiTomato, GiWheat, GiSprout} from 'react-icons/gi';
import {FaBoxesStacked, FaCartShopping, FaChartLine, FaClipboardCheck, FaLeaf, FaRegUser, FaRubleSign, FaStore, FaUsers} from 'react-icons/fa6';
import {MdInventory2, MdOutlineApi, MdOutlineSell, MdWarningAmber, MdWaterDrop, MdInfoOutline, MdLocalShipping} from 'react-icons/md';
import './style.css';
import './analytics.css';
import './auth.css';

const API = import.meta.env.VITE_API_URL || 'http://localhost:8080';
async function api(path, opts = {}) {
  const r = await fetch(API + path, {headers: {'Content-Type': 'application/json'}, ...opts});
  if (!r.ok) throw new Error(await r.text());
  return r.json();
}
const post = (p, b) => api(p, {method: 'POST', body: JSON.stringify(b)});
const num = (v, fallback = 0) => Number(v ?? fallback);

function App() {
  const [session, setSession] = useState(() => localStorage.getItem('agrocrm-session'));
  const [tab, setTab] = useState('dashboard');
  const [data, setData] = useState({});
  const [msg, setMsg] = useState('');
  const [modal, setModal] = useState(null);
  const sessionData = useMemo(() => {
    try { return session ? JSON.parse(session) : null; } catch { return null; }
  }, [session]);
  const activeFarmId = sessionData?.farmId || 1;
  const load = async () => {
    const keys = ['fields', 'crops', 'inventory', 'plantings', 'tasks', 'harvests', 'customers', 'sales'];
    const out = {};
    await Promise.all(keys.map(async k => out[k] = await api(`/farms/${activeFarmId}/${k}`)));
    out.dashboard = await api(`/farms/${activeFarmId}/dashboard`);
    out.products = await api('/public/products');
    setData(out);
  };
  useEffect(() => { if (sessionData) load().catch(e => setMsg(e.message)); }, [activeFarmId, sessionData]);
  const crop = data.crops?.[0], field = data.fields?.[0], harvestItem = data.inventory?.find(i => i.type === 'harvest'), customer = data.customers?.[0], planting = data.plantings?.[0];
  const submitAction = async (kind, form) => {
    if (kind === 'field') await post(`/farms/${activeFarmId}/fields`, {name: form.name, areaHectares: Number(form.areaHectares), location: form.location, soilType: form.soilType, status: form.status});
    if (kind === 'planting') await post(`/farms/${activeFarmId}/plantings`, {fieldID: Number(form.fieldID), cropID: Number(form.cropID), seedQuantityKg: Number(form.seedQuantityKg), expectedYieldKg: Number(form.expectedYieldKg)});
    if (kind === 'inventory') await post(`/farms/${activeFarmId}/inventory`, {type: form.type, name: form.name, cropId: Number(form.cropID || 0), quantityKg: Number(form.quantityKg), minQuantityKg: Number(form.minQuantityKg || 0), averageCostPerKg: Number(form.averageCostPerKg || 0), unit: form.unit || 'кг'});
    if (kind === 'task') await post(`/farms/${activeFarmId}/tasks`, {title: form.title, description: form.description, type: form.type, status: 'todo', dueDate: form.dueDate, fieldID: Number(form.fieldID || 0), plantingID: Number(form.plantingID || 0)});
    if (kind === 'harvest') await post(`/farms/${activeFarmId}/harvests`, {plantingID: Number(form.plantingID || 0), cropID: Number(form.cropID), quantityKg: Number(form.quantityKg), qualityGrade: form.qualityGrade});
    if (kind === 'customer') await post(`/farms/${activeFarmId}/customers`, {name: form.name, phone: form.phone, email: form.email, type: form.type, address: form.address, notes: form.notes});
    if (kind === 'sale') await post(`/farms/${activeFarmId}/sales`, {customerID: Number(form.customerID), inventoryItemID: Number(form.inventoryItemID), quantityKg: Number(form.quantityKg), pricePerKg: Number(form.pricePerKg)});
    setModal(null); setMsg('Данные сохранены'); await load();
  };
  const actions = useMemo(() => ({
    open(kind) { setModal(kind); },
    async updateField(id, form) { await api(`/fields/${id}`, {method: 'PATCH', body: JSON.stringify(form)}); setMsg('Поле обновлено'); await load(); },
    async deleteField(id) { await api(`/fields/${id}`, {method: 'DELETE'}); setMsg('Поле удалено'); await load(); },
    planting() { setModal('planting'); },
    harvest() { setModal('harvest'); },
    sale() { setModal('sale'); },
    async order() { await post('/public/orders', {customerName: 'Кафе Беркат', phone: '+7 900 000 00 00', items: [{productId: harvestItem?.id, quantityKg: 300}]}); setMsg('Внешний заказ принят через публичный API'); load(); }
  }), [activeFarmId, field, crop, planting, customer, harvestItem]);

  const menu = [
    ['dashboard', 'Главная', FiHome], ['fields', 'Поля', FiMapPin], ['plantings', 'Посевы', GiWheat], ['inventory', 'Склад', FaStore], ['tasks', 'Задачи', FaClipboardCheck], ['harvests', 'Урожай', GiPlantRoots], ['customers', 'Клиенты', FaUsers], ['sales', 'Продажи', MdOutlineSell], ['analytics', 'Аналитика', FaChartLine], ['api', 'API', MdOutlineApi], ['settings', 'Настройки', FiSettings]
  ];

  if (!sessionData) return <AuthPage onLogin={(payload) => { localStorage.setItem('agrocrm-session', JSON.stringify(payload)); setSession(JSON.stringify(payload)); }} />;

  return <div className="shell">
    <aside className="sidebar">
      <div className="brand"><div className="logo"><FaLeaf /></div><span>AgroCRM</span></div>
      <nav>{menu.map(([id, title, Icon]) => <button key={id} className={tab === id ? 'active' : ''} onClick={() => setTab(id)}><Icon />{title}</button>)}</nav>
      <div className="farm-card"><div className="farm-img"><GiFarmTractor /></div><b>Ферма Ахмат</b><span>Чеченская Республика</span><em>Овощное хозяйство</em></div>
      <div className="profile"><div><FaRegUser /></div><p><b>Ахмат Исаев</b><span>Владелец фермы</span></p><FiChevronRight /></div>
    </aside>
    <main className="content">
      <Topbar onLogout={() => { localStorage.removeItem('agrocrm-session'); setSession(''); }} />
      {msg && <div className="toast">{msg}</div>}
      {modal && <ActionModal kind={modal} data={data} onClose={() => setModal(null)} onSubmit={submitAction} />}
      {tab === 'dashboard' && <Dashboard data={data} actions={actions} />}
      {tab !== 'dashboard' && <SecondaryPage tab={tab} data={data} actions={actions} />}
    </main>
  </div>;
}

function AuthPage({onLogin}) {
  const [mode, setMode] = useState('login');
  const [login, setLogin] = useState({email: '', password: ''});
  const [form, setForm] = useState({ownerName: '', farmName: '', phone: '', email: '', region: '', landArea: '', businessScale: '', comment: ''});
  const [status, setStatus] = useState('');
  const submitLogin = async (e) => { e.preventDefault(); const r = await post('/auth/login', login); onLogin(r); };
  const submitApplication = async (e) => { e.preventDefault(); const r = await post('/public/applications', form); setStatus(r.message || 'Заявка принята'); setForm({ownerName: '', farmName: '', phone: '', email: '', region: '', landArea: '', businessScale: '', comment: ''}); };
  const set = (key, value) => setForm(prev => ({...prev, [key]: value}));
  return <main className="auth-page">
    <section className="auth-hero"><div className="auth-brand"><div className="logo"><FaLeaf /></div><span>AgroCRM</span></div><h1>CRM для фермеров — доступ выдаётся после заявки</h1><p>Мы собираем данные о хозяйстве, оформляем профиль фермы и выдаём владельцу личный логин и пароль.</p><div className="auth-points"><span><FiCheck/>Профиль под ваше хозяйство</span><span><FiCheck/>Учёт земли, посевов и склада</span><span><FiCheck/>Аналитика прибыли и продаж</span></div></section>
    <section className="auth-grid single">
      <div className="auth-card auth-switch-card"><div className="auth-switch"><button className={mode === 'login' ? 'active' : ''} onClick={() => setMode('login')}>Вход</button><button className={mode === 'request' ? 'active' : ''} onClick={() => setMode('request')}>Заявка на доступ</button></div>{mode === 'login' ? <form className="login-card" onSubmit={submitLogin}><span className="eyebrow">Уже есть доступ</span><h2>Вход в CRM</h2><label><FiMail/><input value={login.email} onChange={e=>setLogin({...login,email:e.target.value})} placeholder="Логин / email" /></label><label><FiLock/><input value={login.password} onChange={e=>setLogin({...login,password:e.target.value})} type="password" placeholder="Пароль" /></label><button className="auth-primary">Войти</button><button type="button" className="auth-demo" onClick={()=>onLogin({farmId:1,name:'Демо'})}>Войти в демо</button><small>Логин и пароль выдаёт команда AgroCRM после подключения.</small></form> : <form className="request-card" onSubmit={submitApplication}><span className="eyebrow">Нужен доступ</span><h2>Заявка на подключение</h2><div className="request-grid"><label><FiUser/><input required value={form.ownerName} onChange={e=>set('ownerName',e.target.value)} placeholder="ФИО предпринимателя" /></label><label><FaLeaf/><input value={form.farmName} onChange={e=>set('farmName',e.target.value)} placeholder="Название хозяйства" /></label><label><FiPhone/><input required value={form.phone} onChange={e=>set('phone',e.target.value)} placeholder="Телефон" /></label><label><FiMail/><input value={form.email} onChange={e=>set('email',e.target.value)} placeholder="Почта" /></label><label><FiMapPin/><input value={form.region} onChange={e=>set('region',e.target.value)} placeholder="Регион" /></label><label><GiFarmTractor/><input value={form.landArea} onChange={e=>set('landArea',e.target.value)} placeholder="Масштаб земли, например 20 га" /></label></div><select value={form.businessScale} onChange={e=>set('businessScale',e.target.value)}><option value="">Формат хозяйства</option><option>Личное подсобное хозяйство</option><option>ИП / малый фермер</option><option>Среднее хозяйство</option><option>Агробизнес с продажами</option></select><textarea value={form.comment} onChange={e=>set('comment',e.target.value)} placeholder="Что выращиваете и какие задачи хотите закрыть?" />{status && <div className="request-status"><FiCheck/>{status}</div>}<button className="auth-primary">Отправить заявку</button></form>}</div>
    </section>
  </main>;
}

function Topbar({onLogout}) { return <header className="topbar"><div className="left"><FiMenu /><b>Ферма Ахмат</b><FiChevronDown /><span><FiMapPin />Чеченская Республика</span></div><label className="search"><FiSearch /><input placeholder="Найти поле, клиента или культуру..." /><kbd>⌘K</kbd></label><div className="right"><div className="bell"><FiBell /><i>3</i></div><FiHelpCircle /><div className="avatar"><FaRegUser /></div><p><b>Ахмат Исаев</b><span>Владелец</span></p><button className="logout-btn" onClick={onLogout}>Выйти</button></div></header> }

function Dashboard({data, actions}) {
  const inv = data.inventory || [];
  const tasks = data.tasks || [];
  const sales = data.sales || [];
  const potato = inv.find(i => i.type === 'harvest');
  const seed = inv.find(i => i.type === 'seed');
  const revenue = num(data.dashboard?.revenue, sales.length ? 35000 : 0);
  const profit = num(data.dashboard?.profit, sales.length ? 20000 : 0);
  const potatoKg = num(potato?.quantity_kg, potato ? 0 : 4800);
  const seedKg = num(seed?.quantity_kg, 700);
  return <>
    <SeasonBanner seedKg={seedKg} potatoKg={potatoKg} />
    <section className="kpis">
      <Kpi icon={<FaRubleSign />} color="green" title="Выручка за сезон" value={`${revenue.toLocaleString('ru-RU')} ₽`} hint="+12% к прошлому сезону" />
      <Kpi icon={<FaChartLine />} color="green" title="Прибыль" value={`${profit.toLocaleString('ru-RU')} ₽`} hint="+15% к прошлому сезону" />
      <Kpi icon={<FaBoxesStacked />} color="green" title="Остаток урожая" value={`${potatoKg.toLocaleString('ru-RU')} кг`} hint="Доступно для продажи" />
      <Kpi icon={<GiSprout />} color="orange" title="Остаток семян" value={`${seedKg.toLocaleString('ru-RU')} кг`} hint="Ниже минимума!" danger />
      <Kpi icon={<FaClipboardCheck />} color="green" title="Ближайшие задачи" value={tasks.length || 4} hint="Требуют внимания" />
      <Kpi icon={<MdInventory2 />} color="violet" title="Внешние заказы" value="2" hint="Новые заказы" />
    </section>
    <ProductPath />
    <section className="dashboard-grid">
      <TasksCard tasks={tasks} />
      <InventoryCard potatoKg={potatoKg} seedKg={seedKg} />
      <AlertsCard />
      <PlantingsCard />
      <SalesCard />
      <ProfitCard profit={profit} />
    </section>
    <QuickActions actions={actions} />
  </>;
}

function SeasonBanner({seedKg, potatoKg}) { return <section className="season-banner"><div><span className="eyebrow">Сезон картофеля · май 2026</span><h1>Картофельная партия под контролем: от 2 гектаров до первой продажи</h1><p>Главный экран показывает только то, что фермеру нужно решить сегодня: хватит ли семян, что делать на поле и сколько продукции уже можно продавать.</p></div><div className="field-ticket"><span>Поле №1</span><b>2 га</b><small>Грозненский район</small><hr/><p><GiSprout /> Семена: {seedKg} кг</p><p><GiPotato /> Товарный картофель: {potatoKg.toLocaleString('ru-RU')} кг</p></div></section> }

function Kpi({icon, color, title, value, hint, danger}) { return <article className="kpi"><div className={`round ${color}`}>{icon}</div><div><span>{title}</span><strong>{value}</strong><small className={danger ? 'danger' : ''}>{danger && '⚠ '}{hint}</small></div></article> }
function ProductPath() { const steps = [[<GiFarmTractor/>, 'Поле', '2 га', 'Поле №1'], [<GiSprout/>, 'Посев', '500 кг', 'Семян картофеля'], [<GiPlantRoots/>, 'Урожай', '5 800 кг', 'Собрано'], [<FaStore/>, 'Склад', '4 800 кг', 'В наличии'], [<FaCartShopping/>, 'Продажа', '1 000 кг', 'Продано'], [<FaRubleSign/>, 'Прибыль', '20 000 ₽', 'За сезон']]; return <section className="path"><div className="section-title"><h2>Путь продукта: от поля до прибыли</h2><button>Подробнее <FiChevronRight /></button></div><div className="path-row">{steps.map((s, i) => <React.Fragment key={s[1]}><div className="path-step"><div className="path-icon">{s[0]}</div><b>{s[1]}</b><span>{s[2]}</span><small>{s[3]}</small></div>{i < steps.length - 1 && <div className="arrow">········→</div>}</React.Fragment>)}</div></section> }
function TasksCard({tasks}) { const rows = [['Полив картофеля', 'Поле №1', '20 мая', 'Сегодня', MdWaterDrop, 'blue'], ['Проверка всходов', 'Поле №1', '22 мая', 'Через 2 дня', FaLeaf, 'green'], ['Закупка семян', 'Склад', '23 мая', 'Через 3 дня', FaCartShopping, 'orange'], ['Обработка поля', 'Поле №1', '25 мая', 'Через 5 дней', FaClipboardCheck, 'green']]; return <Panel title="Ближайшие задачи">{rows.map(([t, sub, date, badge, I, color]) => <div className="list-row" key={t}><div className={`mini ${color}`}><I /></div><p><b>{t}</b><span>{sub}</span></p><time>{date}</time><em>{badge}</em></div>)}<More>Смотреть все задачи</More></Panel> }
function InventoryCard({potatoKg, seedKg}) { const rows = [[<GiPotato/>, 'Картофель товарный', 'Урожай', `${potatoKg.toLocaleString('ru-RU')} кг`, 'Доступно'], [<GiPotato/>, 'Семена картофеля', 'Семена', `${seedKg.toLocaleString('ru-RU')} кг`, 'Низкий остаток'], [<GiFertilizerBag/>, 'Удобрение NPK', 'Удобрения', '50 кг', 'В норме']]; return <Panel title="Склад: остатки">{rows.map(r => <div className="stock-row" key={r[1]}><div className="emoji">{r[0]}</div><p><b>{r[1]}</b><span>{r[2]}</span></p><strong>{r[3]}</strong><em className={r[4].startsWith('Низкий') ? 'low' : ''}>{r[4]}</em></div>)}<More>Перейти на склад</More></Panel> }
function AlertsCard() { const rows = [[MdWarningAmber, 'Низкий остаток семян картофеля', 'Осталось 200 кг, минимум 300 кг', 'warn'], [MdWarningAmber, 'Рекомендуется закупка удобрений', 'Остаток 50 кг, минимум 100 кг', 'warn'], [MdInfoOutline, '2 новых внешних заказа', 'Требуют обработки менеджером', 'info']]; return <Panel title="Предупреждения">{rows.map(([I,t,s,cls]) => <div className={`alert ${cls}`} key={t}><I /><p><b>{t}</b><span>{s}</span></p><FiChevronRight /></div>)}<More>Все уведомления</More></Panel> }
function PlantingsCard() { return <Panel title="Активные посевы"><table><thead><tr><th>Культура</th><th>Поле</th><th>Семена</th><th>Ожидаемый урожай</th><th>Статус</th></tr></thead><tbody><tr><td><span className="crop-cell"><GiPotato />Картофель</span></td><td>Поле №1<br/><span>2 га</span></td><td>500 кг</td><td>6 000 кг</td><td><em>Активный</em></td></tr></tbody></table><More>Все посевы</More></Panel> }
function SalesCard() { return <Panel title="Продажи за сезон"><table><thead><tr><th>Клиент</th><th>Товар</th><th>Кол-во</th><th>Сумма</th><th>Статус</th></tr></thead><tbody><tr><td>Ресторан Кавказ</td><td>Картофель</td><td>1 000 кг</td><td>35 000 ₽</td><td><em>Оплачено</em></td></tr></tbody></table><More>Все продажи</More></Panel> }
function ProfitCard({profit}) { return <Panel title="Прибыль по культурам"><div className="donut"><div><b>{profit.toLocaleString('ru-RU')} ₽</b><span>Общая прибыль</span></div></div><ul className="legend"><li><i></i>Картофель <b>20 000 ₽ (66%)</b></li><li><i></i>Помидоры <b>8 000 ₽ (26%)</b></li><li><i></i>Огурцы <b>3 000 ₽ (8%)</b></li></ul><More>Полная аналитика</More></Panel> }
function QuickActions({actions}) { return <section className="quick"><b>Быстрые действия</b><button onClick={()=>actions.open('field')}><FiPlus />Добавить поле</button><button onClick={actions.planting}><FiPlus />Создать посев</button><button onClick={actions.harvest}><FiPlus />Добавить урожай</button><button onClick={()=>actions.open('customer')}><FiPlus />Добавить клиента</button><button onClick={actions.sale}><FaCartShopping />Новая продажа</button><button onClick={()=>actions.open('inventory')}><GiPlantRoots />Закупка семян</button></section> }
function Panel({title, children}) { return <article className="panel"><h3>{title}</h3>{children}</article> }
function More({children}) { return <button className="more">{children}<FiChevronRight /></button> }
function FieldStats() { const stats = [[GiFarmTractor, 'Всего полей', '6', 'на ферме'], [FaLeaf, 'Общая площадь', '15.7 га', 'все поля'], [GiSprout, 'Засеяно', '8.2 га', '52% от общей площади'], [FaClipboardCheck, 'Готово к посеву', '5.5 га', '35% от общей площади'], [FiRefreshCw, 'Отдыхает', '2.0 га', '13% от общей площади']]; return <section className="field-stats">{stats.map(([Icon, title, value, hint]) => <article className="field-stat" key={title}><div><Icon /></div><p><span>{title}</span><b>{value}</b><small>{hint}</small></p></article>)}</section> }
function FieldsPage({data, actions}) { const [q,setQ]=useState(''); const [status,setStatus]=useState('all'); const [menu,setMenu]=useState(null); const [edit,setEdit]=useState(null); const fields=data.fields||[]; const statusMap={ready:['Готово к посеву','ready'],planted:['Занято посевом','seeded'],resting:['Отдыхает','rest']}; const visible=fields.filter(f=>`${f.name} ${f.location} ${f.soil_type}`.toLowerCase().includes(q.toLowerCase())).filter(f=>status==='all'||f.status===status); return <div className="fields-page"><div className="page-head"><div><h1>Поля</h1><p>Управление вашими полями и участками</p></div><button className="add-field" onClick={()=>actions.open('field')}><FiPlus />Добавить поле</button></div><FieldStats /><section className="fields-card"><div className="fields-toolbar"><div className="tabs"><button className={status==='all'?'active':''} onClick={()=>setStatus('all')}>Все поля</button><button className={status==='planted'?'active':''} onClick={()=>setStatus('planted')}>Активные</button><button className={status==='ready'?'active':''} onClick={()=>setStatus('ready')}>Готовы к посеву</button><button className={status==='resting'?'active':''} onClick={()=>setStatus('resting')}>Отдыхает</button></div><div className="field-controls"><label><FiSearch /><input value={q} onChange={e=>setQ(e.target.value)} placeholder="Поиск по полям..." /></label><button onClick={()=>setStatus('all')}><FiFilter />Сбросить</button><select value={status} onChange={e=>setStatus(e.target.value)}><option value="all">Все статусы</option><option value="ready">Готово к посеву</option><option value="planted">Занято посевом</option><option value="resting">Отдыхает</option></select></div></div><table className="fields-table"><thead><tr><th>Название поля</th><th>Площадь</th><th>Местоположение</th><th>Тип почвы</th><th>Статус</th><th>Последняя активность</th><th>Действия</th></tr></thead><tbody>{visible.map((f, idx) => {const st=statusMap[f.status]||statusMap.ready; return <tr key={f.id}><td><div className="field-name"><div className={`field-thumb f${idx%6+1}`}></div><p><b>{f.name}</b></p></div></td><td>{Number(f.area_hectares||0)} га</td><td>{f.location||'—'}</td><td>{f.soil_type||'—'}</td><td><span className={`field-badge ${st[1]}`}>{st[0]}</span></td><td>{f.updated_at?'Обновлено':'—'}</td><td className="field-actions-cell"><button className="icon-action" onClick={()=>setMenu(menu===f.id?null:f.id)}><FiMoreHorizontal /></button>{menu===f.id&&<div className="row-menu"><button onClick={()=>{setEdit(f);setMenu(null)}}>Изменить</button><button className="danger" onClick={()=>{if(confirm(`Удалить ${f.name}?`)) actions.deleteField(f.id); setMenu(null)}}>Удалить</button></div>}</td></tr>})}</tbody></table><div className="field-footer"><span>Показано {visible.length} из {fields.length} полей</span><div><button><FiChevronLeft /></button><button className="current">1</button><button><FiChevronRight /></button></div></div></section>{edit&&<FieldEditModal field={edit} onClose={()=>setEdit(null)} onSubmit={async form=>{await actions.updateField(edit.id,form);setEdit(null)}}/>}</div> }
function FieldEditModal({field,onClose,onSubmit}){const [form,setForm]=useState({name:field.name||'',areaHectares:field.area_hectares||'',location:field.location||'',soilType:field.soil_type||'',status:field.status||'ready'});const set=(k,v)=>setForm(p=>({...p,[k]:v}));return <div className="modal-backdrop" role="dialog" aria-modal="true"><form className="action-modal" onSubmit={e=>{e.preventDefault();onSubmit(form)}}><button type="button" className="modal-close" onClick={onClose}><FiChevronDown/></button><h2>Изменить поле</h2><p>Обновите данные участка</p><div className="modal-grid"><label><span>Название поля *</span><input value={form.name} onChange={e=>set('name',e.target.value)}/></label><label><span>Площадь, га</span><input type="number" value={form.areaHectares} onChange={e=>set('areaHectares',e.target.value)}/></label><label><span>Местоположение</span><input value={form.location} onChange={e=>set('location',e.target.value)}/></label><label><span>Статус</span><select value={form.status} onChange={e=>set('status',e.target.value)}><option value="ready">Готово к посеву</option><option value="planted">Занято посевом</option><option value="resting">Отдыхает</option></select></label><label><span>Тип почвы</span><input value={form.soilType} onChange={e=>set('soilType',e.target.value)}/></label></div><div className="modal-actions"><button type="button" onClick={onClose}>Отмена</button><button className="save-settings">Сохранить</button></div></form></div>}
function PlantingStats() { const stats = [[GiWheat, 'Активных посевов', '5', 'из 8 запланированных', 'green'], [FaLeaf, 'Площадь в посевах', '12.5 га', '+2.3 га к прошлому сезону', 'green'], [FaClipboardCheck, 'Ожидаемый урожай', '24 800 кг', '+18% к прошлому сезону', 'orange'], [GiPlantRoots, 'Собрано урожая', '5 800 кг', '23% от плана', 'green'], [MdInventory2, 'Культур выращивается', '4', 'Картофель, томаты, огурцы, лук', 'violet']]; return <section className="planting-stats">{stats.map(([Icon, title, value, hint, color]) => <article className="planting-stat" key={title}><div className={color}><Icon /></div><p><span>{title}</span><b>{value}</b><small>{hint}</small></p></article>)}</section> }
function CropIcon({type}) { const icons = {potato: GiPotato, tomato: GiTomato, cucumber: GiPlantRoots, wheat: GiGrain, onion: GiSprout, corn: GiCorn, carrot: GiCarrot}; const I = icons[type] || GiSprout; return <I /> }
function Progress({label, value}) { return <div className="progress-cell"><span>{label}</span><div><i style={{width: `${value}%`}}></i></div><b>{value}%</b></div> }
