function AnalyticsPage({data}) {
  const sales = data.sales || [];
  const tasks = data.tasks || [];
  const revenue = num(data.dashboard?.revenue, sales.length ? 248500 : 248500);
  const profit = num(data.dashboard?.profit, sales.length ? 86200 : 86200);
  const expenses = Math.max(revenue - profit, 162300);
  const soldKg = sales.reduce((sum, sale) => sum + num(sale.quantity_kg), 0) || 5900;
  const kpis = [
    [GiSprout, 'Выручка', `${revenue.toLocaleString('ru-RU')} ₽`, '+18% к прошлому месяцу', 'green'],
    [FaStore, 'Прибыль', `${profit.toLocaleString('ru-RU')} ₽`, '+21% к прошлому месяцу', 'green'],
    [FaChartLine, 'Расходы', `${expenses.toLocaleString('ru-RU')} ₽`, '+12% к прошлому месяцу', 'orange'],
    [FaBoxesStacked, 'Продано продукции', `${soldKg.toLocaleString('ru-RU')} кг`, '+16% к прошлому месяцу', 'blue'],
    [FaUsers, 'Новые клиенты', '7', '+3 к прошлому месяцу', 'violet']
  ];
  const crops = [
    ['Картофель', 40, 99400, 'green'], ['Томаты', 25, 62100, 'red'], ['Огурцы', 15, 37300, 'blue'], ['Пшеница', 10, 24800, 'sky'], ['Кукуруза', 5, 12900, 'orange'], ['Другие', 5, 11000, 'gray']
  ];
  const months = [['Дек 25',120],['Янв 26',135],['Фев 26',160],['Мар 26',190],['Апр 26',210],['Май 26',248]];
  const top = [['🥔','Картофель','42 600 ₽','+25%','up'],['🍅','Томаты','18 900 ₽','+18%','up'],['🥒','Огурцы','12 300 ₽','+12%','up'],['🌾','Пшеница','8 700 ₽','-5%','down'],['🌽','Кукуруза','3 800 ₽','+7%','up']];
  const taskStatus = [['Выполнено','14 (50%)','green'],['В процессе','8 (29%)','blue'],['Просрочено','4 (14%)','orange'],['Отменено','2 (7%)','gray']];
  return <div className="analytics-page">
    <div className="page-head analytics-head"><div><h1>Аналитика</h1><p>Ключевые показатели и аналитика по ферме</p></div><button className="date-range"><FiCalendar />01.05.2026 – 31.05.2026<FiChevronDown /></button></div>
    <section className="analytics-kpis">{kpis.map(([Icon,t,v,h,c])=><article className="analytics-kpi" key={t}><div className={c}><Icon/></div><p><span>{t}</span><b>{v}</b><small>{h}</small></p></article>)}</section>
    <section className="analytics-grid top">
      <article className="analytics-card line-card"><CardTitle title="Выручка и прибыль" action="По дням"/><div className="chart-legend"><span><i className="green"></i>Выручка</span><span><i className="blue"></i>Прибыль</span></div><LineChart /></article>
      <article className="analytics-card revenue-card"><CardTitle title="Структура выручки по культурам" action="По сумме"/><div className="revenue-layout"><div className="revenue-donut"><div><b>{revenue.toLocaleString('ru-RU')} ₽</b><span>Всего</span></div></div><ul className="revenue-list">{crops.map(c=><li key={c[0]}><i className={c[3]}></i><span>{c[0]}</span><b>{c[1]}%</b><strong>{c[2].toLocaleString('ru-RU')} ₽</strong></li>)}</ul></div></article>
    </section>
    <section className="analytics-grid bottom">
      <article className="analytics-card"><CardTitle title="Продажи по месяцам" action="По месяцам"/><div className="bar-chart">{months.map(([m,v])=><div className="bar-col" key={m}><span>{v} тыс.</span><div style={{height:`${v}px`}}></div><small>{m}</small></div>)}</div></article>
      <article className="analytics-card"><h3>Топ культур по прибыли</h3><table className="profit-table"><thead><tr><th>Культура</th><th>Прибыль</th><th>Динамика</th></tr></thead><tbody>{top.map(r=><tr key={r[1]}><td><span>{r[0]}</span>{r[1]}</td><td>{r[2]}</td><td className={r[4]}>{r[3]} {r[4]==='up'?'↑':'↓'}</td></tr>)}</tbody></table></article>
      <article className="analytics-card task-card"><h3>Статус задач</h3><div className="task-layout"><div className="task-donut"><div><span>Всего</span><b>{tasks.length || 28}</b></div></div><ul className="task-status-list">{taskStatus.map(s=><li key={s[0]}><i className={s[2]}></i><span>{s[0]}</span><b>{s[1]}</b></li>)}</ul></div></article>
    </section>
    <p className="analytics-updated"><FiRefreshCw />Данные обновлены 31.05.2026 в 09:30</p>
  </div>
}
